/***
 * Compile Period: last_week_baseline
 * Handles campaign, adgroup, and keyword rows from merged input.
 ***/
const PERIOD = 'last_week_baseline';
const rows = $input.all().map(i => i.json || {});

function toNum(v) {
  if (v == null || v === '') return 0;
  const n = Number(String(v).replace(/,/g,'.').replace(/[^0-9.\-]/g,''));
  return Number.isFinite(n) ? n : 0;
}
