    ...c,
    ctr:  safeDiv(c.clk,   c.imp),
    cpc:  safeDiv(c.spend, c.clk),
    cvr:  safeDiv(c.conv,  c.clk),
    roas: safeDiv(c.value, c.spend),
  }));
  const totals = {imp:0, clicks:0, spend:0, conv:0, value:0};
