function toNum(v) {
  if (v == null || v === '') return 0;
  const n = Number(String(v).replace(/,/g,'.').replace(/[^0-9.\-]/g,''));
  return Number.isFinite(n) ? n : 0;
}
function normChannel(v) {
  const s = String(v || '').toUpperCase().replace(/[_\s]/g,' ').trim();
  if (s.includes('SEARCH')) return 'SEARCH';
  if (s.includes('PERFORMANCE') || s.includes('PMAX') || s.includes('MAX')) return 'PERFORMANCE MAX';
  return s || 'OTHER';
}
const safeDiv = (n, d) => (d && Number.isFinite(n) && Number.isFinite(d)) ? n/d : 0;

// ── Level detection ──────────────────────────────────────────
const isCampaign = r => !('adgroup_id' in r);
const isAdgroup  = r => 'adgroup_id' in r && !('keyword' in r);
const isKeyword  = r => 'keyword' in r;

const campaignRows = rows.filter(isCampaign);
const adgroupRows  = rows.filter(isAdgroup);
