// MindMeister - Last month budget
const BRAND = "MindMeister";
const MODE = "last";
const MONTHS = ["January","February","March","April","May","June","July","August","September","October","November","December"];
const now = new Date();
const monthName = MODE === "last" ? MONTHS[(now.getMonth()+11)%12] : MONTHS[now.getMonth()];
const rows = $input.all().map(i => i.json);
function labelOf(r){ const k=Object.keys(r).find(x=>/^col[\s_]*1$/i.test(x))||Object.keys(r)[0]; return String(r?.[k]??"").trim(); }
function findRow(t){ const w=t==="sum"?"summe":"leftover"; let r=rows.find(r=>labelOf(r).toLowerCase()===w); if(!r) r=rows.find(r=>Number(r.row_number)===(t==="sum"?43:44)); return r; }
function toNum(v){ if(typeof v==="number") return v; if(v==null||v==="") return 0; const s=String(v).trim().replace(/\s/g,"").replace(/[€]/g,"").replace(/\./g,"").replace(/,/g,".").replace(/[^\d.\-]/g,""); const n=Number(s); return Number.isFinite(n)?n:0; }
function fmtEUR(n){ return `€${n.toLocaleString("de-DE",{minimumFractionDigits:2,maximumFractionDigits:2})}`; }
const rowSum=findRow("sum"), rowLeft=findRow("left");
const spend=toNum(rowSum?.[monthName]), leftover=toNum(rowLeft?.[monthName]);
const budget=spend+leftover, pct=budget?Number(((spend/budget)*100).toFixed(1)):0;
return [{ json: { source:BRAND, month_name:monthName, total_budget:budget, total_spend:spend, leftover, pct_spent:pct, summary_text:`Total budget: ${fmtEUR(budget)} — total spend: ${fmtEUR(spend)} (${pct}% used, ${fmtEUR(leftover)} left)` } }];

const items = $input.all().map(i => i.json);
if (items.length !== 2) throw new Error(`Expected 2 items, got ${items.length}`);
const out = { brand: 'MM', last: null, prev: null };
for (const it of items) {
  if (it.period === 'last_month') out.last = it;
  else if (it.period === 'prev_month') out.prev = it;
}
if (!out.last || !out.prev) throw new Error('Could not identify last/prev month: ' + items.map(i=>i.period).join(', '));
return [{ json: out }];

/*** Prep Monthly for Agent - MM only ***/
const all = $input.all().map(i => i.json);
const mmBundle = all.find(i => i.brand === 'MM' && ('last' in i || 'prev' in i));
const budget   = all.find(i => i.source === 'MindMeister' || i.pct_spent !== undefined);
if (!mmBundle) throw new Error('No MM bundle: ' + JSON.stringify(all.map(i => Object.keys(i))));
const last = mmBundle.last || {}, prev = mmBundle.prev || {};
const pct  = (n, d) => (Number.isFinite(n) && Number.isFinite(d) && d !== 0) ? (n-d)/d : null;
const mom  = { spend: pct(last.totals?.spend, prev.totals?.spend),
               conv:  pct(last.totals?.conv,  prev.totals?.conv),
               roas:  pct(last.totals?.roas,  prev.totals?.roas),
               ctr:   pct(last.totals?.ctr,   prev.totals?.ctr),
               cpc:   pct(last.totals?.cpc,   prev.totals?.cpc),
               clicks:pct(last.totals?.clicks,prev.totals?.clicks) };
const MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const now = new Date();
const mn = MONTHS[(now.getMonth()+11)%12], yr = now.getMonth()===0 ? now.getFullYear()-1 : now.getFullYear();
return [{ json: { monthly_payload: { MM: { last, prev, mom,
  per_channel: last.by_channel||{},
  highs_lows: { top3: last.top3_labels||[], bottom3: last.bottom3_labels||[] },
  budget: budget||null }, meta: { generated_at_iso: new Date().toISOString(),
  month_label: `${mn} ${yr}`, brand:'MM', type:'monthly' } } } }];

/***
 * Format Monthly Slack Blocks — Strategic Review
 * Purpose: Full-picture monthly assessment with regional breakdown and strategic recs
 * Read time: 5-7 minutes
 ***/
const all     = $input.all().map(i => i.json);
const data    = all.find(i => i.monthly_payload !== undefined) || all[0];
const ai      = (all.find(i => i.output !== undefined) || {}).output || '';
const payload = data.monthly_payload || {};
const mm      = payload.MM || {};
const meta    = payload.meta || {};

const last      = mm.last?.totals    || {};
const prev      = mm.prev?.totals    || {};
const mom       = mm.mom             || {};
const budget    = mm.budget           || {};
const ch        = mm.last?.by_channel || {};
const campaigns = mm.last?.campaigns  || [];

const fmtEur  = n => `€${Number(n||0).toLocaleString('de-DE',{minimumFractionDigits:2,maximumFractionDigits:2})}`;
const fmtNum  = n => Number(n||0).toLocaleString('de-DE');
const fmtRoas = n => Number(n||0).toFixed(2);
const fmtMom  = n => n==null ? 'n/a' : `${n>=0?'+':''}${(n*100).toFixed(0)}%`;
const arrow   = n => n == null ? '' : n > 0.005 ? '▲' : n < -0.005 ? '▼' : '→';

// MoM table
const rows = [
  ['Spend',       fmtEur(last.spend),                   fmtEur(prev.spend),                   `${arrow(mom.spend)} ${fmtMom(mom.spend)}`],
  ['Clicks',      fmtNum(last.clicks),                  fmtNum(prev.clicks),                  `${arrow(mom.clicks)} ${fmtMom(mom.clicks)}`],
  ['Conversions', fmtNum(last.conv),                    fmtNum(prev.conv),                    `${arrow(mom.conv)} ${fmtMom(mom.conv)}`],
  ['Efficiency',  fmtRoas(last.roas),                   fmtRoas(prev.roas),                   `${arrow(mom.roas)} ${fmtMom(mom.roas)}`],
  ['CPC',         fmtEur(last.cpc),                     fmtEur(prev.cpc),                     `${arrow(mom.cpc)} ${fmtMom(mom.cpc)}`],
  ['CTR',         `${((last.ctr||0)*100).toFixed(2)}%`, `${((prev.ctr||0)*100).toFixed(2)}%`, `${arrow(mom.ctr)} ${fmtMom(mom.ctr)}`],
];
const col = (s, w) => String(s).padEnd(w);
const tableLines = [
  `${col('Metric',13)}| ${col('This month',18)}| ${col('Prev month',18)}| MoM`,
  '─'.repeat(60),
  ...rows.map(([m,l,p,d]) => `${col(m,13)}| ${col(l,18)}| ${col(p,18)}| ${d}`)
].join('\n');

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: `📆 MM Monthly – ${meta.month_label || 'Last Month'}`, emoji: true } },
  { type: 'section', text: { type: 'mrkdwn', text: `\`\`\`${tableLines}\`\`\`` } },
];

// Budget
if (budget.total_budget > 0) {
  const pct = Math.round(budget.pct_spent || 0);
  const filled = Math.min(10, Math.round(pct / 10));
  const bar = '█'.repeat(filled) + '░'.repeat(10 - filled);
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn',
      text: `*Budget* \`${bar}\` ${pct}%  ·  ${fmtEur(budget.total_spend)} of ${fmtEur(budget.total_budget)}  ·  ${fmtEur(budget.leftover)} remaining`
    }
  });
}

// Channel breakdown with spend share
const chKeys = Object.keys(ch);
if (chKeys.length > 0) {
  const chLines = chKeys.map(k => {
    const b = ch[k];
    const label = k === 'PERFORMANCE_MAX' ? 'PMax' : k;
    const share = last.spend > 0 ? ((b.spend / last.spend) * 100).toFixed(0) : 0;
    return `• *${label}* (${share}% of spend): ${fmtEur(b.spend)} · eff. ${fmtRoas(b.roas)} · ${fmtNum(b.clicks)} clicks · CTR ${((b.ctr||0)*100).toFixed(2)}% · CPC ${fmtEur(b.cpc)} · ${fmtNum(b.conv)} conv`;
  }).join('\n');
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Channel breakdown*\n${chLines}` } });
}

// Regional breakdown — parse first segment of campaign name (DACH, UK, US, BR, FR, ES, JA)
if (campaigns.length > 0) {
  const regions = {};
  for (const c of campaigns) {
    const region = (c.name || 'OTHER').split('_')[0];
    if (!regions[region]) regions[region] = { spend: 0, conv: 0, value: 0 };
    regions[region].spend += c.spend || 0;
    regions[region].conv  += c.conv  || 0;
    regions[region].value += c.value || 0;
  }
  const regionLines = Object.entries(regions)
    .sort(([,a],[,b]) => b.spend - a.spend)
    .map(([r, d]) => {
      const eff = d.spend > 0 ? (d.value / d.spend).toFixed(2) : '—';
      return `• *${r}*: ${fmtEur(d.spend)} · ${fmtNum(Math.round(d.conv))} conv · eff. ${eff}`;
    }).join('\n');
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Regional breakdown*\n${regionLines}` } });
}

// Top 5 / Bottom 5 campaigns (≥€50 spend)
const ranked  = campaigns.filter(c => c.spend >= 50).sort((a,b) => b.roas - a.roas);
const top5    = ranked.slice(0, 5);
const bottom5 = [...ranked].reverse().slice(0, 5);
if (top5.length || bottom5.length) {
  blocks.push({ type: 'divider' });
  blocks.push({
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*🏆 Top 5 campaigns*\n${top5.map((c,i)=>`${i+1}. ${c.name}\n   eff. ${fmtRoas(c.roas)} · ${fmtEur(c.spend)}`).join('\n') || 'n/a'}` },
      { type: 'mrkdwn', text: `*⚠️ Underperformers*\n${bottom5.map((c,i)=>`${i+1}. ${c.name}\n   eff. ${fmtRoas(c.roas)} · ${fmtEur(c.spend)}`).join('\n') || 'n/a'}` },
    ]
  });
}

// 3 strategic recommendations from Claude
if (ai) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*💡 Strategic recommendations*\n${ai.slice(0,3000)}` } });
}

blocks.push({ type: 'divider' });

// Data depth note
const depthData = mm.last;
if (depthData) {
  const ag = depthData.adgroups || {};
  const kw = depthData.keywords || {};
  const agNote = ag.total_rows > 0
    ? (ag.has_names ? `${ag.total_rows} rows · names available` : `${ag.total_rows} rows · names pending in export`)
    : 'not loaded';
  const kwNote = kw.total_rows > 0
    ? (kw.has_names ? `${kw.total_rows} rows · names available` : `${kw.total_rows} rows · names pending in export`)
    : 'not loaded';
  blocks.push({ type: 'divider' });
  blocks.push({
    type: 'context',
    elements: [{ type: 'mrkdwn',
      text: `_Data depth — Campaigns: ${depthData.campaigns?.length || 0} · Ad groups: ${agNote} · Keywords: ${kwNote}_`
    }]
  });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `_MindMeister Paid · Monthly Review · ${meta.month_label || ''}_` }] });

const fallback = `📆 MM Monthly – ${meta.month_label || 'Last Month'} | Spend: ${fmtEur(last.spend)} (${fmtMom(mom.spend)} MoM) | Eff: ${fmtRoas(last.roas)} (${fmtMom(mom.roas)})`;
return [{ json: { blocks, blocksStr: JSON.stringify(blocks), text: fallback } }];
